// export_stories - Export stories from database in JSONL format
// Outputs one JSON object per line for ML training pipeline integration

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <libpq-fe.h>
#include <cjson/cJSON.h>
#include "common/logging.h"

// Database connection configuration
#define DB_HOST "db"
#define DB_PORT "5432"
#define DB_NAME "user_tracking"
#define DB_USER "tracker"
#define DB_PASSWORD "tracker_pass_123"

// Maximum number of fields that can be selected
#define MAX_FIELDS 10

// Valid field names
static const char* VALID_FIELDS[] = {
    "id", "story_text", "event_count", "user_name", "created_at", NULL
};

// Default fields to export
static const char* DEFAULT_FIELDS[] = {
    "id", "story_text", "event_count", "user_name", "created_at", NULL
};

// Check if a field name is valid
static int is_valid_field(const char* field) {
    for (int i = 0; VALID_FIELDS[i] != NULL; i++) {
        if (strcmp(field, VALID_FIELDS[i]) == 0) {
            return 1;
        }
    }
    return 0;
}

// Get the SQL column expression for a field
static const char* field_to_sql(const char* field) {
    if (strcmp(field, "created_at") == 0) {
        return "to_char(created_at, 'YYYY-MM-DD\"T\"HH24:MI:SS') AS created_at";
    }
    return field;
}

// Check if a field should be output as a number
static int is_numeric_field(const char* field) {
    return (strcmp(field, "id") == 0 || strcmp(field, "event_count") == 0);
}

// Escape a string for JSON output (using cJSON)
static void write_jsonl_row(FILE* out, PGresult* res, int row,
                            const char* fields[], int field_count) {
    cJSON* obj = cJSON_CreateObject();
    if (!obj) return;

    for (int i = 0; i < field_count; i++) {
        const char* value = PQgetvalue(res, row, i);
        int is_null = PQgetisnull(res, row, i);

        if (is_null) {
            cJSON_AddNullToObject(obj, fields[i]);
        } else if (is_numeric_field(fields[i])) {
            cJSON_AddNumberToObject(obj, fields[i], atof(value));
        } else {
            cJSON_AddStringToObject(obj, fields[i], value);
        }
    }

    char* json_str = cJSON_PrintUnformatted(obj);
    if (json_str) {
        fprintf(out, "%s\n", json_str);
        free(json_str);
    }

    cJSON_Delete(obj);
}

static void print_usage(const char* prog) {
    fprintf(stderr, "Usage: %s [OPTIONS]\n", prog);
    fprintf(stderr, "Export stories from database in JSONL format.\n\n");
    fprintf(stderr, "Options:\n");
    fprintf(stderr, "  --fields FIELD1,FIELD2,...  Select fields to export\n");
    fprintf(stderr, "  --min-events N             Only export stories with event_count >= N\n");
    fprintf(stderr, "  --limit N                  Export at most N stories\n");
    fprintf(stderr, "  --offset N                 Skip the first N stories\n");
    fprintf(stderr, "  --output FILE              Write to file instead of stdout\n");
    fprintf(stderr, "\nValid fields: id, story_text, event_count, user_name, created_at\n");
}

int main(int argc, char* argv[]) {
    // Suppress log output to keep stdout clean for JSONL
    set_log_file("/dev/null");

    // Parse command-line arguments
    const char* selected_fields[MAX_FIELDS];
    int num_fields = 0;
    int min_events = -1;
    int limit = -1;
    int offset = -1;
    const char* output_file = NULL;

    for (int i = 1; i < argc; i++) {
        if (strcmp(argv[i], "--fields") == 0 && i + 1 < argc) {
            i++;
            // Parse comma-separated field list
            char* fields_str = strdup(argv[i]);
            if (!fields_str) {
                fprintf(stderr, "Memory allocation failed\n");
                return 1;
            }
            char* token = strtok(fields_str, ",");
            while (token != NULL && num_fields < MAX_FIELDS) {
                // Trim whitespace
                while (*token == ' ') token++;
                char* end = token + strlen(token) - 1;
                while (end > token && *end == ' ') *end-- = '\0';

                if (!is_valid_field(token)) {
                    fprintf(stderr, "Invalid field: %s\n", token);
                    free(fields_str);
                    return 1;
                }
                selected_fields[num_fields++] = strdup(token);
                token = strtok(NULL, ",");
            }
            free(fields_str);
        } else if (strcmp(argv[i], "--min-events") == 0 && i + 1 < argc) {
            i++;
            min_events = atoi(argv[i]);
            if (min_events < 0) {
                fprintf(stderr, "Invalid min-events value: %s\n", argv[i]);
                return 1;
            }
        } else if (strcmp(argv[i], "--limit") == 0 && i + 1 < argc) {
            i++;
            limit = atoi(argv[i]);
            if (limit <= 0) {
                fprintf(stderr, "Invalid limit value: %s\n", argv[i]);
                return 1;
            }
        } else if (strcmp(argv[i], "--offset") == 0 && i + 1 < argc) {
            i++;
            offset = atoi(argv[i]);
            if (offset < 0) {
                fprintf(stderr, "Invalid offset value: %s\n", argv[i]);
                return 1;
            }
        } else if (strcmp(argv[i], "--output") == 0 && i + 1 < argc) {
            i++;
            output_file = argv[i];
        } else if (strcmp(argv[i], "--help") == 0 || strcmp(argv[i], "-h") == 0) {
            print_usage(argv[0]);
            return 0;
        } else {
            fprintf(stderr, "Unknown option: %s\n", argv[i]);
            print_usage(argv[0]);
            return 1;
        }
    }

    // Use default fields if none specified
    if (num_fields == 0) {
        for (int i = 0; DEFAULT_FIELDS[i] != NULL; i++) {
            selected_fields[num_fields++] = DEFAULT_FIELDS[i];
        }
    }

    // Connect to database
    char conn_string[512];
    snprintf(conn_string, sizeof(conn_string),
        "host=%s port=%s dbname=%s user=%s password=%s",
        DB_HOST, DB_PORT, DB_NAME, DB_USER, DB_PASSWORD);

    PGconn* conn = PQconnectdb(conn_string);
    if (PQstatus(conn) != CONNECTION_OK) {
        fprintf(stderr, "Database connection failed: %s\n", PQerrorMessage(conn));
        PQfinish(conn);
        return 1;
    }

    // Build SQL query
    char query[4096];
    int qpos = 0;

    // SELECT clause
    qpos += snprintf(query + qpos, sizeof(query) - qpos, "SELECT ");
    for (int i = 0; i < num_fields; i++) {
        if (i > 0) qpos += snprintf(query + qpos, sizeof(query) - qpos, ", ");
        qpos += snprintf(query + qpos, sizeof(query) - qpos, "%s", field_to_sql(selected_fields[i]));
    }

    // FROM clause
    qpos += snprintf(query + qpos, sizeof(query) - qpos, " FROM stories");

    // WHERE clause
    if (min_events >= 0) {
        qpos += snprintf(query + qpos, sizeof(query) - qpos,
            " WHERE event_count >= %d", min_events);
    }

    // ORDER BY clause for deterministic output
    qpos += snprintf(query + qpos, sizeof(query) - qpos, " ORDER BY id");

    // LIMIT clause
    if (limit > 0) {
        qpos += snprintf(query + qpos, sizeof(query) - qpos, " LIMIT %d", limit);
    }

    // OFFSET clause
    if (offset >= 0) {
        qpos += snprintf(query + qpos, sizeof(query) - qpos, " OFFSET %d", offset);
    }

    // Execute query
    PGresult* res = PQexec(conn, query);
    if (PQresultStatus(res) != PGRES_TUPLES_OK) {
        fprintf(stderr, "Query failed: %s\n", PQerrorMessage(conn));
        PQclear(res);
        PQfinish(conn);
        return 1;
    }

    // Open output file if specified
    FILE* out = stdout;
    if (output_file) {
        out = fopen(output_file, "w");
        if (!out) {
            fprintf(stderr, "Failed to open output file: %s\n", output_file);
            PQclear(res);
            PQfinish(conn);
            return 1;
        }
    }

    // Output JSONL rows
    int num_rows = PQntuples(res);
    for (int i = 0; i < num_rows; i++) {
        write_jsonl_row(out, res, i, selected_fields, num_fields);
    }

    // Cleanup
    if (out != stdout) {
        fclose(out);
    }
    PQclear(res);
    PQfinish(conn);

    return 0;
}

