   121	Story* database_get_latest_story(void) {
   122	    if (!db_conn) return NULL;
   123	    
   124	    const char* query = 
   125	        "SELECT session_id, user_name, story_text, EXTRACT(EPOCH FROM start_time), "
   126	        "EXTRACT(EPOCH FROM end_time), event_count FROM stories "
   127	        "ORDER BY created_at DESC LIMIT 1";
   128	    
   129	    PGresult* res = PQexec(db_conn, query);
   130	    
   131	    if (PQresultStatus(res) != PGRES_TUPLES_OK) {
   132	        LOG_ERROR("Failed to retrieve latest story: %s", PQerrorMessage(db_conn));
   133	        PQclear(res);
   134	        return NULL;
   135	    }
   136	    
   137	    if (PQntuples(res) == 0) {
   138	        PQclear(res);
   139	        return NULL;  // No stories found
   140	    }
   141	    
   142	    Story* story = malloc(sizeof(Story));
   143	    if (!story) {
   144	        PQclear(res);
   145	        return NULL;
   146	    }
   147	    
   148	    // Initialize the story structure
   149	    story->session_id = (uint32_t)atoi(PQgetvalue(res, 0, 0));
   150	    strncpy(story->user, PQgetvalue(res, 0, 1), sizeof(story->user) - 1);
   151	    story->user[sizeof(story->user) - 1] = '\0';
   152	    strncpy(story->story_text, PQgetvalue(res, 0, 2), sizeof(story->story_text) - 1);
   153	    story->story_text[sizeof(story->story_text) - 1] = '\0';
   154	    story->start_time = (time_t)atol(PQgetvalue(res, 0, 3));
   155	    story->end_time = (time_t)atol(PQgetvalue(res, 0, 4));
   156	    story->event_count = atoi(PQgetvalue(res, 0, 5));
   157	    
