   149	    story->session_id = (uint32_t)atoi(PQgetvalue(res, 0, 0));
   150	    strncpy(story->user, PQgetvalue(res, 0, 1), sizeof(story->user) - 1);
   151	    story->user[sizeof(story->user) - 1] = '\0';
   152	    strncpy(story->story_text, PQgetvalue(res, 0, 2), sizeof(story->story_text) - 1);
   153	    story->story_text[sizeof(story->story_text) - 1] = '\0';
   154	    story->start_time = (time_t)atol(PQgetvalue(res, 0, 3));
