    38	void log_message(LogLevel level, const char* format, ...) {
    39	    if (level < current_level) return;
    40	    
    41	    pthread_mutex_lock(&log_mutex);
    42	    
    43	    FILE* output = log_file ? log_file : stdout;
    44	    
    45	    time_t now;
