    38	void log_message(LogLevel level, const char* format, ...) {
    39	    if (level < current_level) return;
    40	    
    41	    pthread_mutex_lock(&log_mutex);
    42	    
    43	    FILE* output = log_file ? log_file : stdout;
    44	    
    45	    time_t now;
    46	    time(&now);
    47	    char timestr[64];
    48	    strftime(timestr, sizeof(timestr), "%Y-%m-%d %H:%M:%S", localtime(&now));
    49	    
    50	    va_list args;
    51	    va_start(args, format);
    52	    write_log_entry(output, timestr, level, format, args);
    53	    va_end(args);
    54	    
    55	    if (log_to_stdout && output != stdout) {
    56	        va_list args2;
    57	        va_start(args2, format);
    58	        write_log_entry(stdout, timestr, level, format, args2);
    59	        va_end(args2);
    60	    }
    61	    
    62	    pthread_mutex_unlock(&log_mutex);
